private static float[] initializeCharCounts(int currentMode) {
    float[] charCounts;
    if (currentMode == ASCII_ENCODATION) {
        charCounts = new float[]{0, 1, 1, 1, 1, 1.25f};
    } else {
        charCounts = new float[]{1, 2, 2, 2, 2, 2.25f};
        charCounts[currentMode] = 0;
    }
    return charCounts;
}

private static int determineEncoding(float[] charCounts) {
    int minIndex = findMinimumIndex(charCounts);
    return ENCODING_MAP.get(minIndex);
}

private static int findMinimumIndex(float[] charCounts) {
    int minIndex = 0;
    for (int i = 1; i < 6; i++) {
        if (charCounts[i] < charCounts[minIndex]) {
            minIndex = i;
        }
    }
    return minIndex;
}

private static boolean shouldReturnEncoding(float[] charCounts) {
    return isConditionMet(charCounts, ASCII_ENCODATION) ||
           (isConditionMet(charCounts, BASE256_ENCODATION) && charCounts[BASE256_ENCODATION] > 0) ||
           (isConditionMet(charCounts, EDIFACT_ENCODATION) && charCounts[EDIFACT_ENCODATION] > 0) ||
           (isConditionMet(charCounts, TEXT_ENCODATION) && charCounts[TEXT_ENCODATION] > 0) ||
