    return minCount == 1 && (encodingType == BASE256_ENCODATION || encodingType == EDIFACT_ENCODATION || encodingType == TEXT_ENCODATION || encodingType == X12_ENCODATION);
}

private static int getMinimumCount(float minValue) {
    return (int) Math.min(minValue, 5);
}

