class CommandLineOptions {
  private String[] args;
  private BarcodeFormat barcodeFormat;
  private String imageFormat;
  private String outFileString;
  private int width;
  private int height;
  private String contents;

  public CommandLineOptions(String[] args) {
    this.args = args;
    this.barcodeFormat = DEFAULT_BARCODE_FORMAT;
    this.imageFormat = DEFAULT_IMAGE_FORMAT;
    this.outFileString = DEFAULT_OUTPUT_FILE;
    this.width = DEFAULT_WIDTH;
    this.height = DEFAULT_HEIGHT;
    this.contents = null;
    parseArgs();
  }

  private void parseArgs() {
    for (String arg : args) {
      String[] argValue = arg.split("=");
      switch (argValue[0]) {
        case "--barcode_format":
          barcodeFormat = BarcodeFormat.valueOf(argValue[1]);
          break;
        case "--image_format":
          imageFormat = argValue[1];
          break;
        case "--output":
          outFileString = argValue[1];
          break;
        case "--width":
          width = Integer.parseInt(argValue[1]);
          break;
        case "--height":
          height = Integer.parseInt(argValue[1]);
          break;
        default:
          if (arg.startsWith("-")) {
            System.err.println("Unknown command line option " + arg);
            printUsage();
            return;
          }
          contents = arg;
          break;
      }
    }
  }

  public String getBarcodeFormat() {
    return barcodeFormat;
  }

  public String getContents() {
    return contents;
  }

  public String getImageFormat() {
    return imageFormat;
  }

  public String getOutFile() {
    return outFileString;
  }

  public int getWidth() {
    return width;
  }

  public int getHeight() {
    return height;
  }

  public boolean isContentsMissing() {
    return contents == null;
  }

  public void printUsage() {
    // Print usage
  }
}
