import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.time.LocalDateTime;
import java.util.Optional;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.zip.DataFormatException;

public static String translateString(String english, String language) throws IOException {
    if ("en".equalsIgnoreCase(language)) {
        return english;
    }
    Optional<String> massagedLanguage = Optional.ofNullable(LANGUAGE_CODE_MASSAGINGS.get(language));
    if (massagedLanguage.isPresent()) {
        language = massagedLanguage.get();
    }
    System.out.println("Need translation for " + english);

    long now = LocalDateTime.now().toEpochMilli();
    if (now < nextAllowedAPICallTime) {
        long timeToWait = nextAllowedAPICallTime - now;
        if (timeToWait > 0) {
            try {
                Thread.sleep(timeToWait);
            } catch (InterruptedException ie) {
                // continue
            }
        }
    }
    nextAllowedAPICallTime = now + MIN_API_CALL_INTERVAL_MS;

    try (URL translateURL = new URL("http://ajax.googleapis.com/ajax/services/language/translate?v=1.0&q=" + URLEncoder.encode(english, "UTF-8") + "&langpair=en%7C" + language);
         BufferedReader in = new BufferedReader(new InputStreamReader(translateURL.openStream(), StandardCharsets.UTF_8))) {

        Pattern TRANSLATE_RESPONSE_PATTERN = Pattern.compile("<translation>(.*?)<\/translation>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL);
        Matcher m = TRANSLATE_RESPONSE_PATTERN.matcher(in);
        if (!m.find()) {
            System.err.println("No translate result");
            return english;
        }
        String translation = m.group(1);
        System.out.println("Got translation " + translation);

        // This is a little crude; unescape some common escapes in the raw response
        translation = translation.replace("\\\\u0026quot;", "\"")
                                .replace("\\\\u0026#39;", "'")
                                .replace("\\\\u200b", "");

        return translation;
    }
}
