  private static int calculateModuleSize(BitMatrix image) {
    int height = image.getHeight();
    int width = image.getWidth();
    int minDimension = Math.min(height, width);
    int[] leftTopBlack = image.getTopLeftOnBit();
    if (leftTopBlack == null) {
      throw NotFoundException.getNotFoundInstance();
    }
    int x = leftTopBlack[0];
    int y = leftTopBlack[1];
    while (x < minDimension && y < minDimension && image.get(x, y)) {
      x++;
      y++;
    }
    return x - leftTopBlack[0];
  }

  private static int calculateDimension(int width, int height, int moduleSize) {
    // Find the rightmost black module on the first row
    int rowEndOfSymbol = width - 1;
    while (rowEndOfSymbol > 0 && !image.get(rowEndOfSymbol, 0)) {
      rowEndOfSymbol--;
    }
    if (rowEndOfSymbol == 0) {
      throw NotFoundException.getNotFoundInstance();
    }
    rowEndOfSymbol++;

    // Make sure width of barcode is a multiple of module size
    if ((rowEndOfSymbol - 0) % moduleSize != 0) {
      throw NotFoundException.getNotFoundInstance();
    }
    int backOffAmount = moduleSize == 1 ? 1 : moduleSize >> 1;
    return 1 + ((rowEndOfSymbol - 0) / moduleSize) - backOffAmount;
  }

  private static BitMatrix readBits(BitMatrix image, int dimension, int moduleSize) {
    BitMatrix bits = new BitMatrix(dimension);
    for (int i = 0; i < dimension; i++) {
      int iOffset = 0 + i * moduleSize;
      for (int j = 0; j < dimension; j++) {
        if (image.get(0 + j * moduleSize, iOffset)) {
          bits.set(j, i);
        }
      }
    }
    return bits;
  }
}
