public static OpenCamera open(int cameraId) {
    int numCameras = Camera.getNumberOfCameras();
    if (numCameras == 0) {
        Log.w(TAG, "No cameras!");
        return null;
    }

    Camera.CameraInfo selectedCameraInfo = null;
    int index = getCameraIndex(cameraId, numCameras);

    Camera camera = openCamera(index, numCameras);

    if (camera == null) {
        return null;
    }

    return new OpenCamera(index, camera, determineCameraFacing(selectedCameraInfo), selectedCameraInfo.orientation);
}

private static int getCameraIndex(int cameraId, int numCameras) {
    boolean explicitRequest = cameraId >= 0;
    int index = explicitRequest ? cameraId : 0;

    if (explicitRequest) {
        Camera.getCameraInfo(index, selectedCameraInfo);
    } else {
        for (int i = 0; i < numCameras; i++) {
            Camera.CameraInfo cameraInfo = new Camera.CameraInfo();
            Camera.getCameraInfo(i, cameraInfo);
            if (CameraFacing.BACK.equals(CameraFacing.valueOf(cameraInfo.facing))) {
                selectedCameraInfo = cameraInfo;
                break;
            }
        }
    }

    return index;
}

private static Camera openCamera(int index, int numCameras) {
    if (index < numCameras) {
        Log.i(TAG, "Opening camera #" + index);
        return Camera.open(index);
    } else {
        if (conditionForExplicitRequest(index, numCameras)) {
            Log.w(TAG, "Requested camera does not exist: " + index);
            return null;
        } else {
            Log.i(TAG, "No camera facing " + CameraFacing.BACK + "; returning camera #0");
            return Camera.open(0);
        }
    }
}

private static CameraFacing determineCameraFacing(Camera.CameraInfo info) {
    return CameraFacing.values()[info.facing];
}

private static boolean conditionForExplicitRequest(int index, int numCameras) {
    return index >= 0 && index < numCameras;
}
```

