                    result += (daysRented - 3) * 1.5;
                break;
            default:
                throw new IllegalArgumentException("Unknown price code: " + priceCode);
        }
        return result;
    }

    public int getFrequentRenterPoints(int priceCode, int daysRented) {
        if (priceCode == NEW_RELEASE && daysRented > 1)
            return 2;
        return 1;
    }
