  private void convertImageToLuminance(BufferedImage src, int srcLeft, int srcTop, int width, int height) {
    if (EXPLICIT_LUMINANCE_CONVERSION) {
      explicitLuminanceConversion(src, srcLeft, srcTop, width, height);
    } else {
      implicitLuminanceConversion(src, srcLeft, srcTop, width, height);
    }
  }

  private void explicitLuminanceConversion(BufferedImage src, int srcLeft, int srcTop, int width, int height) {
    WritableRaster srcRaster = src.getRaster();
    int[] buffer = new int[width];
    for (int y = srcTop; y < srcTop + height; y++) {
      srcRaster.getPixels(srcLeft, y, width, 1, buffer, 0, src.getWidth());
      for (int x = 0; x < width; x++) {
        int pixel = buffer[x];
        if ((pixel & 0xFF000000) == 0) {
          pixel = 0xFFFFFFFF; // = white
        }
        // .229R + 0.587G + 0.114B (YUV/YIQ for PAL and NTSC)
        buffer[x] = 
            (306 * ((pixel >> 16) & 0xFF) +
             601 * ((pixel >> 8) & 0xFF) +
             117 * (pixel & 0xFF) +
             0x200) >> 10;
      }
      getRaster().setPixels(left, top, width, 1, buffer);
    }
  }

  private void implicitLuminanceConversion(BufferedImage src, int srcLeft, int srcTop, int width, int height) {
    if (src.getAlphaRaster() != null) {
      processAlpha(src, srcLeft, srcTop, width, height);
    }
    createGrayscaleCopy(src, left, top);
  }

  private void processAlpha(BufferedImage src, int srcLeft, int srcTop, int width, int height) {
    int[] buffer = new int[width];
    for (int y = srcTop; y < srcTop + height; y++) {
      src.getRGB(srcLeft, y, width, 1, buffer, 0, src.getWidth());
      boolean rowChanged = false;
      for (int x = 0; x < width; x++) {
        if ((buffer[x] & 0xFF000000) == 0) {
          buffer[x] = 0xFFFFFFFF; // = white
          rowChanged = true;
        }
      }
      if (rowChanged) {
        src.setRGB(srcLeft, y, width, 1, buffer, 0, src.getWidth());
      }
    }
  }

  private void createGrayscaleCopy(BufferedImage src, int left, int top) {
    src.getGraphics().drawImage(src, 0, 0, null);
  }
}
