```java
int encodeChar(char c, StringBuilder sb) {
    switch (getCategoricalValue(c)) {
        case SPACE:
            sb.append('\3');
            return 1;
        case DIGIT:
            sb.append((char) (c - 48 + 4));
            return 1;
        case UPPERCASE_LETTER:
            sb.append((char) (c - 65 + 14));
            return 1;
        case LOWER_CASE_LETTER_OR_SYMBOL:
            sb.append('\0'); //Shift 1 Set
            sb.append(c);
            return 2;
        case UPPERCASE_SYMBOL:
            sb.append('\1'); //Shift 2 Set
            sb.append((char) (c - 33));
            return 2;
        case SYMBOL_1:
            sb.append('\1'); //Shift 2 Set
            sb.append((char) (c - 58 + 15));
            return 2;
        case SYMBOL_2:
            sb.append('\1'); //Shift 2 Set
            sb.append((char) (c - 91 + 22));
            return 2;
        case SPECIAL_CHARACTERS:
            sb.append('\2'); //Shift 3 Set
            sb.append((char) (c - 96));
            return 2;
        default:
            sb.append("\1\u001e"); //Shift 2, Upper Shift
            int len = 2;
            len += encodeChar((char) (c - 128), sb);
            return len;
    }
}

private int getCategoricalValue(char c) {
    switch (c) {
        case ' ':
            return SPACE;
        case '0' | '1' | ... | '9':
            return DIGIT;
